INSERT INTO DOI_ACCT (YYYY,SEL_CODE,SITE,ACCT_CLASS,계정과목내부코드,전표기표여부,ACCT,ACCT_NAME,차대,계정대분류,관리항목유형,계정과목Lev,상위계정과목,상위계정과목내부코드,소분류,중분류,대분류,EXPEN_SEL,EXPEN_SEL명)
SELECT YYYY,SEL_CODE,SITE,ACCT_CLASS,계정과목내부코드,전표기표여부,ACCT,ACCT_NAME,차대,계정대분류,관리항목유형,계정과목Lev,상위계정과목,상위계정과목내부코드,소분류,중분류대분류,EXPEN_SEL,EXPEN_SEL명
FROM (
	SELECT *, MAX(seq_no) over (partition by YYYY, SITE, ACCT) max_seq_no FROM #TempTable
)A
WHERE 1=1
AND seq_no = max_seq_no
AND NOT EXISTS (
	SELECT 1
	FROM DOI_ACCT b
	WHERE 1=1
	AND b.YYYY = a.YYYY
	AND b.SITE = a.SITE
	AND b.ACCT = a.ACCT
);

DROP TABLE #TempTable;

INSERT INTO DOI_ACCT
(
YYYY
, SEL_CODE
, SITE
, ACCT_CLASS
, 계정과목내부코드
, 전표기표여부
, ACCT
, ACCT_NAME
, 차대
, 계정대분류
, 관리항목유형
, 계정과목Lev
, 상위계정과목
, 상위계정과목내부코드
, 소분류
, 중분류
, 대분류
, EXPEN_SEL
, EXPEN_SEL명
)
VALUES
(
#{yyyy}
, #{selCode}
, CASE WHEN #{site}='본사' Then 'HQ'  WHEN #{site}='베트남' then 'VN' else left(#{site},2) end
, CASE WHEN #{acctClass}='가공비' Then 'AA'  WHEN #{acctClass}='판매관리비' then 'BB' else left(#{acctClass},2) end
, #{acctItnCode}
, #{acctIssued}
, #{acct}
, #{acctName}
, #{debitCredit}
, #{largeAcct}
, #{mngItemType}
, #{acctLev}
, #{upperAcct}
, #{upperAcctItnCode}
, #{smallClass}
, #{midClass}
, #{largeClass}
, #{expenSel}
, #{expenSelName}
);

mapper.delete:
DELETE FROM DOI_ACCT
WHERE 1=1
and yyyy = #{yyyy}
and sel_code = #{selCode}
and site = #{siteOrg}
and acct_class = #{acctClassOrg}
and acct = #{acct}

DELETE FROM dw_공정별_모니터링항목
WHERE LINE=#{line}
AND PROCESS_ID=#{processId} 
AND 공정코드=#{공정코드}
AND 모니터링구분=#{모니터링구분}
AND 모니터링항목=#{모니터링항목}
;

mapper.update:
UPDATE DOI_ACCT
SET SEL_CODE = #{selCode}
,ACCT_CLASS = CASE WHEN #{acctClass} ='가공비' Then 'AA'  WHEN #{acctClass}='판매관리비' then 'BB' else left(#{acctClass},2) end
,계정과목내부코드 = #{acctItnCode}
,전표기표여부 = #{acctIssued}
,ACCT_NAME = #{acctName}
,차대 = #{debitCredit}
,계정대분류 = #{largeAcct}
,관리항목유형 = #{mngItemType}
,계정과목Lev = #{acctLev}
,상위계정과목 = #{upperAcct}
,상위계정과목내부코드 = #{upperAcctItnCode}
,소분류 = #{smallClass}
,중분류 = #{midClass}
,대분류 = #{largeClass}
,EXPEN_SEL = #{expenSel}
,EXPEN_SEL명 = #{expenSelName}
WHERE 1=1
and yyyy = #{yyyy}
and site = #{siteOrg}
and acct = #{acct}
;

UPDATE dw_공정별_모니터링항목
SET 공정명 = #{공정명},
	등급및수량 = #{등급및수량},
	검증부서 = #{검증부서},
	순서 = #{순서},
	설비유형_수동_대수 = #{설비유형수동대수},
	설비유형_자동_대수 = #{설비유형자동대수}
WHERE LINE=#{line}
AND PROCESS_ID=#{processId} 
AND 공정코드=#{공정코드}
AND 모니터링구분=#{모니터링구분}
AND 모니터링항목=#{모니터링항목}
;
